    function render_param(setting) {

        rapid_combat.checked = !!parent.helper.pro.misc.rapidCombat && setting.rapidCombat;

        rebuild_armory.checked = !!parent.helper.pro.misc.rebuildArmory && setting.rebuildArmory;

        reset.checked = setting.reset;

        rapid_combat.disabled = !parent.helper.pro.misc.rapidCombat;

        rebuild_armory.disabled = !parent.helper.pro.misc.rebuildArmory;

        reset.disabled = rapid_combat.disabled && rebuild_armory.disabled;

    }

    

    function apply_param() {

        parent.helper.pro.misc.dailyRank.apply({rapidCombat: rapid_combat.checked, rebuildArmory:rebuild_armory.checked, reset:reset.checked});

    }

